def _extract_system_message(messages: list[dict[str, Any]]) -> Tuple[str | None, list[dict[str, Any]]]:
    if not messages:
        return None, []

    system_msg = messages[0]
    if system_msg.get("role") == "system":
        return system_msg.get("content"), messages[1:]
    else:
        return None, messages

class AnthropicChat(ChatProvider):
    def __init__(self, auth: AuthProvider, model: str | None, tier: ModelTier, models: dict[ModelTier, str] | None):
        self.auth = auth
        self.model = model or CHAT_MODELS[tier]
        self.client = anthropic.Anthropic(
            api_key=auth.get_headers()["x-api-key"],
            http_client=httpx.Client(),
        )

    def chat(self, messages: list[dict[str, Any]]) -> str:
        system_msg, other_messages = _extract_system_message(messages)
        response = self.client.messages.create(
            model=self.model,
            max_tokens=1024,
            system=system_msg or "",
            messages=other_messages
        )
        return response.content[0].text

    def chat_stream(self, messages: list[dict[str, Any]]) -> Iterator[str]:
        system_msg, other_messages = _extract_system_message(messages)
        stream = self.client.messages.stream(
            model=self.model,
            max_tokens=1024,
            system=system_msg or "",
            messages=other_messages
        )
        for chunk in stream:
            if chunk.type == "content_block_delta" and chunk.delta.text is not None:
                yield chunk.delta.text

