    def __init__(self, model: str | None, tier: ModelTier, base_url: str | None, models: dict[ModelTier, str] | None):
        self.model = model or CHAT_MODELS[tier]
        self.base_url = base_url or DEFAULT_BASE_URL
        self.client = httpx.Client(base_url=self.base_url)

    def chat(self, messages: list[dict[str, Any]]) -> str:
        response = self.client.post(
            "/api/generate",
            json={
                "model": self.model,
                "prompt": messages[-1]["content"] if messages else "",
                "stream": False
            }
        )
        return response.json()["response"]

    def chat_stream(self, messages: list[dict[str, Any]]) -> Iterator[str]:
        # Ollama stream endpoint
        stream = self.client.post(
            "/api/generate",
            json={
                "model": self.model,
                "prompt": messages[-1]["content"] if messages else "",
                "stream": True
            },
            stream=True
        )
        for line in stream.iter_lines():
            data = json.loads(line)
            if "response" in data:
                yield data["response"]

    def __del__(self) -> None:
        pass  # No need to explicitly close client as it's managed by httpx

