class OllamaRerank(RerankProvider):
    def __init__(self, model: str | None, base_url: str | None):
        self.model = model or RERANK_MODEL
        self.base_url = base_url or DEFAULT_BASE_URL
        self.client = httpx.Client(base_url=self.base_url)

    def rerank(self, query: str, documents: list[str], top_n: int | None) -> list[RerankResult]:
        results = []
        for i, doc in enumerate(documents):
            score = self._score_document(query, doc)
            results.append(RerankResult(score=score, index=i))  # Adjusted to use RerankResult
        return sorted(results, key=lambda x: x.score, reverse=True)[:top_n if top_n else len(results)]

    def _score_document(self, query: str, document: str) -> float:
        response = self.client.post(
            "/api/rerank",
            json={"model": self.model, "query": query, "documents": [document]}
        )
        data = response.json()
        if "results" in data and len(data["results"]):
            return float(self._parse_score(json.dumps(data["results"])))  # Simplified parsing
        else:
            raise ValueError("Unexpected rerank response")

    def _parse_score(self, content: str) -> float:
        try:
            data = json.loads(content)
            if isinstance(data, list) and len(data) > 0 and "relevance_score" in data[0]:
                return float(data[0]["relevance_score"])
        except (json.JSONDecodeError, KeyError):
            pass
        return 0.0

    def __del__(self) -> None:
        pass

